import os

b64 = ''
favicon_str = f'<link rel="icon" type="image/png" href="data:image/png;base64,{b64}" />'

target_dir = r'C:\Users\venelouis\Desktop\REPOS\Rullst\cargo-rullst\src\blueprints'
for root, _, files in os.walk(target_dir):
    for f in files:
        if f.endswith('.rs'):
            filepath = os.path.join(root, f)
            with open(filepath, 'r', encoding='utf-8') as file:
                content = file.read()
            
            # Add to every <head> that doesn't have it yet
            if '<head>' in content and 'type="image/png"' not in content:
                content = content.replace('<head>', f'<head>\n            {favicon_str}')
                with open(filepath, 'w', encoding='utf-8') as file:
                    file.write(content)
                print(f'Updated {f}')
